def _is_valid_vec(self, begin: int, end: int) -> bool:
    """A cxx::vector<Space*> should have 2..64 elements."""
    if not begin or not end or end < begin:
        return False
    ptr_size = self.r._ptr_size()
    count = (end - begin) // ptr_size
    return 2 <= count < 64

def _find_continuous_spaces(self, heap: int) -> Tuple[int, int]:
    """
    Return (begin, end) of the cxx::vector<ContinuousSpace*>.
    Uses nominal offset from Heap offsets, then heuristic scan if invalid.
    """
    ptr_size = self.r._ptr_size()
    nominal_off = self.r._hp_off.get('continuous_spaces_', 0)

    begin = self.r.ptr(heap + nominal_off)
    end   = self.r.ptr(heap + nominal_off + ptr_size)
    if self._is_valid_vec(begin, end):
        return begin, end

    # Heuristic: scan forward within 0x2000 bytes by ptr_size steps
    for off in range(0, 0x2000, ptr_size):
        b = self.r.ptr(heap + off)
        e = self.r.ptr(heap + off + ptr_size)
        if self._is_valid_vec(b, e):
            # Sanity: first space pointer should be readable
            sp = self.r.ptr(b)
            if sp and self.r.core.find_block(sp):
                return b, e
    return 0, 0

def walk(self):
    heap = self._heap_addr()
    if not heap:
        return
    begin, end = self._find_continuous_spaces(heap)
    if not begin or not end:
        # Last resort: linear scan of all writable LoadBlocks
        yield from self._fallback_scan()
        return
    ptr_size = self.r._ptr_size()
    pos = begin
    while pos < end:
        space_ptr = self.r.ptr(pos)
        pos += ptr_size
        if space_ptr:
            yield from self._walk_space(space_ptr)

def _walk_space(self, space: int):
    rs_off  = self.r._rs_off
    rgn_off = self.r._rgn_off
    num_regions = self.r.u64(space + rs_off.get('num_regions_', 0))
    regions_ptr = self.r.ptr(space + rs_off.get('regions_', 0)) if rs_off.get('regions_', 0) else 0
    # Only treat as RegionSpace if regions_ptr is a plausible heap address (> 64KB)
    if 0 < num_regions < 65536 and regions_ptr > 0x10000:
        yield from self._walk_region_space(space, rs_off, rgn_off)
    else:
        # Fallback: linear scan using ContinuousSpace begin_/end_
        # begin_ and end_ are at stable offsets in ContinuousSpace
        cs_begin_off = self.r.ini.offsets.get('ContinuousSpace', {}).get('begin_', 40)
        cs_end_off   = self.r.ini.offsets.get('ContinuousSpace', {}).get('end_',   48)
        sp_begin = self.r.ptr(space + cs_begin_off)
        sp_end   = self.r.ptr(space + cs_end_off)
        if sp_begin and sp_end and sp_end > sp_begin and (sp_end - sp_begin) < 512 * 1024 * 1024:
            yield from self._linear_scan(sp_begin, sp_end)

def _walk_region_space(self, space: int, rs_off: dict, rgn_off: dict):
    num_regions = self.r.u64(space + rs_off['num_regions_'])
    regions_ptr = self.r.ptr(space + rs_off['regions_'])
    if not regions_ptr:
        return
    rgn_size = resolve_size('Region', self.r.sdk, self.r.bits, self.r.ini) or 64
    for i in range(num_regions):
        r_ptr = regions_ptr + i * rgn_size
        state = self.r.u32(r_ptr + rgn_off.get('state_', 32)) & 0xFF
        rtype = self.r.u32(r_ptr + rgn_off.get('type_',  33)) & 0xFF
        if state == kRegionStateFree:
            continue
        begin = self.r.ptr(r_ptr + rgn_off.get('begin_', 8))
        top   = self.r.ptr(r_ptr + rgn_off.get('top_',   16))
        if not begin or not top or top <= begin:
            continue
        if rtype == kRegionTypeLarge:
            if self.r.is_valid_object(begin):
                yield begin
        elif rtype != kRegionTypeLargeTail:
            yield from self._linear_scan(begin, top)

def _linear_scan(self, begin: int, end: int):
    pos = begin
    while pos < end:
        if self.r.is_valid_object(pos):
            yield pos
            sz = (self.r.obj_size_of(pos) + 7) & ~7
            pos += max(sz, 8)
        else:
            pos += 8

def _fallback_scan(self):

class HeapWalker:
    def __init__(self, reader: ArtReader, runtime_addr: int):
        self.r  = reader
        self.rt = runtime_addr

    def _heap_addr(self) -> int:
        heap_off = self.r._rt_off.get('heap_', 0)
        return self.r.ptr(self.rt + heap_off)

    def _is_valid_vec(self, begin: int, end: int) -> bool:
        """A cxx::vector<Space*> should have 2..64 elements."""
        if not begin or not end or end < begin:
            return False
        ptr_size = self.r._ptr_size()
        count = (end - begin) // ptr_size
        return 2 <= count < 64

    def _find_continuous_spaces(self, heap: int) -> Tuple[int, int]:
        """
        Return (begin, end) of the cxx::vector<ContinuousSpace*>.
        Uses nominal offset from Heap offsets, then heuristic scan if invalid.
        """
        ptr_size = self.r._ptr_size()
        nominal_off = self.r._hp_off.get('continuous_spaces_', 0)

        begin = self.r.ptr(heap + nominal_off)
        end   = self.r.ptr(heap + nominal_off + ptr_size)
        if self._is_valid_vec(begin, end):
            return begin, end

def cmd_class(core: CoreFile, sdk: int, runtime_addr: int, classname: str,
              show_field=True, show_static=True, show_method=False,
              show_impl=False, ini: IniOverrides = _NO_INI):
    reader = ArtReader(core, sdk, ini)
    walker = HeapWalker(reader, runtime_addr)
    # Build match target: if classname contains '.' or '/', treat as fully qualified
    # Otherwise match by simple name (last component of descriptor)
    if '.' in classname or '/' in classname:
        target_desc = 'L' + classname.replace('.', '/') + ';'
        simple_match = False
    else:
        target_desc = classname
        simple_match = True
    found = False
    print(f"[SDK={sdk}] Scanning heap for class: {classname}")
    for obj_addr in walker.walk():
        if not reader.is_class_obj(obj_addr):
            continue
        desc = reader.class_descriptor(obj_addr)
        if not desc:
            continue
        if simple_match:
            # Match by exact simple class name (last component, no inner class suffix)
            # desc format: 'Lsome/package/ClassName;' or 'Lsome/package/Outer$Inner;'
            inner = desc.rstrip(';')
            last = inner.rsplit('/', 1)[-1] if '/' in inner else inner.lstrip('L')
            if last != target_desc:
                continue
        else:
            if desc != target_desc:
                continue
        found = True
        _print_class(reader, obj_addr, show_field, show_static, show_method, show_impl)
        break
    if not found:
        print(f"Class '{classname}' not found in heap.")


def _print_class(reader: ArtReader, cls_ptr: int,
                 show_field: bool, show_static: bool,
                 show_method: bool, show_impl: bool):
    name = reader.pretty_descriptor(cls_ptr)
    super_ptr = reader.class_super(cls_ptr)
    super_name = reader.pretty_descriptor(super_ptr) if super_ptr else None
    print(f"\n[0x{cls_ptr:x}]")
    if super_name:
        print(f"class {name} extends {super_name} {{")
    else:
        print(f"class {name} {{")

    if show_impl:
        iftable = reader.class_iftable(cls_ptr)
        if iftable:
            count = reader.iftable_count(iftable)
            if count > 0:
                print("  // Implements:")
                for i in range(min(count, 64)):
                    iface = reader.iftable_interface(iftable, i)
                    if iface:
                        print(f"    {reader.pretty_descriptor(iface)}")

    if show_static:
        fields = reader.class_static_fields(cls_ptr)
        if fields:
            print("  // Class static fields:")
            for fptr in sorted(fields, key=lambda f: reader.field_offset(f)):
                off   = reader.field_offset(fptr)
                flags = _pretty_access(reader.field_access_flags(fptr))
                typ   = _pretty_descriptor(reader.field_type_descriptor(fptr))
                fname = reader.field_name(fptr)
